public sealed class DefaultNameSplitMember : NameSplitMember
{
    public sealed override bool IsMatch(ProfileMap options, TypeDetails sourceType, Type destType, Type destMemberType, string nameToSearch, List<MemberInfo> resolvers, bool isReverseMap)
    {
        MemberInfo matchingMemberInfo = null;
        int index = 1;
        for (; index < nameToSearch.Length; index++)
        {
            if (char.IsUpper(nameToSearch[index]) && Found())
            {
                return true;
            }
        }
        return matchingMemberInfo != null && Found();
        bool Found()
        {
            var first = nameToSearch[..index];
            matchingMemberInfo = Parent.GetSourceMember(sourceType, destType, destMemberType, first);
            if (matchingMemberInfo == null)
            {
                return false;
            }
            resolvers.Add(matchingMemberInfo);
            var second = nameToSearch[index..];
            var details = options.CreateTypeDetails(matchingMemberInfo.GetMemberType());
            if (Parent.IsMatch(options, details, destType, destMemberType, second, resolvers, isReverseMap))
            {
                return true;
            }
            resolvers.RemoveAt(resolvers.Count - 1);
            return false;
        }
    }
}

public static string[] PossibleNames(string memberName, List<string> prefixes, List<string> postfixes)
    {
        List<string> result = null;
        foreach (var prefix in prefixes)
        {
            if (!memberName.StartsWith(prefix, StringComparison.OrdinalIgnoreCase))
            {
                continue;
            }
            var withoutPrefix = memberName[prefix.Length..];
            result ??= [];
            result.Add(withoutPrefix);
            PostFixes(ref result, postfixes, withoutPrefix);
        }
        PostFixes(ref result, postfixes, memberName);
        return result == null ? [] : [.. result];
        static void PostFixes(ref List<string> result, List<string> postfixes, string name)
        {
            foreach (var postfix in postfixes)
            {
                if (!name.EndsWith(postfix, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }
                result ??= [];
                result.Add(name[..^postfix.Length]);
            }
        }
    }

public virtual double? ReadAsDouble()
        {
            JsonToken t = GetContentToken();

            switch (t)
            {
                case JsonToken.None:
                case JsonToken.Null:
                case JsonToken.EndArray:
                    return null;
                case JsonToken.Integer:
                case JsonToken.Float:
                    object v = Value!;
                    if (v is double d)
                    {
                        return d;
                    }

#if HAVE_BIG_INTEGER
                    if (v is BigInteger value)
                    {
                        d = (double)value;
                    }
                    else
#endif
                    {
                        d = Convert.ToDouble(v, CultureInfo.InvariantCulture);
                    }

                    SetToken(JsonToken.Float, d, false);

                    return (double)d;
                case JsonToken.String:
                    return ReadDoubleString((string?)Value);
            }

            throw JsonReaderException.Create(this, "Error reading double. Unexpected token: {0}.".FormatWith(CultureInfo.InvariantCulture, t));
        }

public virtual bool? ReadAsBoolean()
        {
            JsonToken t = GetContentToken();

            switch (t)
            {
                case JsonToken.None:
                case JsonToken.Null:
                case JsonToken.EndArray:
                    return null;
                case JsonToken.Integer:
                case JsonToken.Float:
                    bool b;
#if HAVE_BIG_INTEGER
                    if (Value is BigInteger integer)
                    {
                        b = integer != 0;
                    }
                    else
#endif
                    {
                        b = Convert.ToBoolean(Value, CultureInfo.InvariantCulture);
                    }

                    SetToken(JsonToken.Boolean, b, false);
                    return b;
                case JsonToken.String:
                    return ReadBooleanString((string?)Value);
                case JsonToken.Boolean:
                    return (bool)Value!;
            }

            throw JsonReaderException.Create(this, "Error reading boolean. Unexpected token: {0}.".FormatWith(CultureInfo.InvariantCulture, t));
        }

